const data = $json || {};

const asString = (value) => {
  if (value === null || value === undefined) return '';
  if (typeof value === 'string') return value;
  try {
    return JSON.stringify(value);
  } catch {
    return String(value);
  }
};

const htmlToText = (html) => asString(html)
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/gi, ' ')
  .replace(/&amp;/gi, '&')
  .replace(/&quot;/gi, '"')
  .replace(/&#39;/gi, "'")
  .replace(/\s+/g, ' ')
  .trim();

const extractAddress = (value) => {
  if (!value) return '';
  if (typeof value === 'string') {
    const match = value.match(/<?([A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,})>?/i);
    return match ? match[1].toLowerCase() : value.trim().toLowerCase();
  }
  if (Array.isArray(value)) {
    for (const item of value) {
      const found = extractAddress(item);
      if (found) return found;
    }
    return '';
  }
  if (typeof value === 'object') {
    if (typeof value.address === 'string') return value.address.trim().toLowerCase();
    if (Array.isArray(value.value)) {
      for (const item of value.value) {
        const found = extractAddress(item);
        if (found) return found;
      }
    }
    if (typeof value.text === 'string') {
      const found = extractAddress(value.text);
      if (found) return found;
    }
  }
  return '';
};

const formatAddress = (value) => {
  if (!value) return '';
  if (typeof value === 'string') return value.trim();
  if (Array.isArray(value)) {
    const items = value.map((item) => formatAddress(item)).filter(Boolean);
    return items.join(', ');
  }
  if (typeof value === 'object') {
    if (Array.isArray(value.value) && value.value.length > 0) {
      const first = value.value[0] || {};
      const name = asString(first.name).trim();
      const address = asString(first.address).trim();
      if (name && address) return `${name} <${address}>`;
      return name || address || asString(value.text).trim();
    }
    if (typeof value.text === 'string') return value.text.trim();
    const name = asString(value.name).trim();
    const address = asString(value.address).trim();
    if (name && address) return `${name} <${address}>`;
    return name || address;
  }
  return asString(value).trim();
};

const subject = asString(data.subject).trim();
const text = asString(data.text).replace(/\u00a0/g, ' ').trim();
const html = asString(data.html);
const htmlText = htmlToText(html);
const fromDisplay = formatAddress(data.from) || formatAddress(data.sender) || formatAddress(data.replyTo) || 'невідомо';
const fromEmail = extractAddress(data.from) || extractAddress(data.sender) || extractAddress(data.replyTo);
const toDisplay = formatAddress(data.to) || formatAddress(data.deliveredTo);
const toRaw = `${asString(data.to)} ${asString(data.deliveredTo)}`.trim();
const combined = [subject, text, htmlText].filter(Boolean).join('\n');

const recipientEmail =
 /lekov00@gmail\.com/i.test(toRaw) ? 'lekov00@gmail.com' :
 /arsen\.k111999@gmail\.com/i.test(toRaw) ? 'arsen.k111999@gmail.com' :
 /tukroschu@gmail\.com/i.test(toRaw) ? 'tukroschu@gmail.com' :
 '';

const accountName =
 recipientEmail === 'lekov00@gmail.com' ? 'Олени' :
 (recipientEmail === 'arsen.k111999@gmail.com' || recipientEmail === 'tukroschu@gmail.com') ? 'Арсена' :
 'невідомого';

const routeMode = recipientEmail === 'lekov00@gmail.com' ? 'alpine_vpn_only' : 'mac_primary';
const targetGoClawModel = recipientEmail === 'lekov00@gmail.com' ? 'goclaw:surveys-olena' : 'goclaw:surveys-arsen';
const allowMacOpen = routeMode !== 'alpine_vpn_only';
const allowAlpineExecution = routeMode === 'alpine_vpn_only';
const trustedSender = fromEmail === 'no-reply@meinungsplatz.ch';
const senderAllowed = trustedSender;
const workflowMarker = asString(data.workflowMarker || data.debugMarker).trim();
const primaryBaseUrl = asString(data.primaryBaseUrl).trim() || process.env.SURVEYS_GCLAW_PRIMARY_BASE_URL || 'http://100.84.163.96:18790';
const fallbackBaseUrl = asString(data.fallbackBaseUrl).trim() || process.env.SURVEYS_GCLAW_FALLBACK_BASE_URL || 'http://100.113.140.25:18790';
const vpnCountryRequired = 'CH';
const vpnCountryOverride = asString(data.vpnCountryOverride || data.alpineVpnCountryOverride).trim().toUpperCase();
const hrefLinks = [...html.matchAll(/href=["']([^"'#]+)["']/gi)].map((m) => m[1]);
const rawLinks = [...(`${text}\n${html}`).matchAll(/https?:\/\/[^\s<>"')\]]+/gi)].map((m) => m[0]);
const cleanLink = (url) => asString(url).trim().replace(/[),.;]+$/g, '').replace(/&amp;/g, '&');
const uniqueLinks = [...new Set([...hrefLinks, ...rawLinks].map(cleanLink).filter(Boolean))];

const scoreLink = (url) => {
  const u = url.toLowerCase();
  let score = 0;
  if (/meinungsplatz|survey|sondage|enquete|questionnaire|poll|study|task|invite|invitation|continue|start|befrag|umfrage/.test(u)) score += 6;
  if (/token=|auth=|session=|survey=|questionnaire=|invite=|invitation=/.test(u)) score += 3;
  if (/unsubscribe|privacy|impress|contact|help|support|facebook|instagram|linkedin|twitter|x\.com|beehiiv/.test(u)) score -= 10;
  if (/https?:\/\//.test(u)) score += 1;
  return score;
};

const sortedLinks = uniqueLinks
  .map((url) => ({ url, score: scoreLink(url) }))
  .sort((a, b) => b.score - a.score);

const topLink = sortedLinks.length ? sortedLinks[0] : null;
const taskLink = topLink && topLink.score >= 4 ? topLink.url : null;
const rewardMatch =
  combined.match(/\b(\d+(?:[.,]\d{1,2})?)\s*CHF\b/i) ||
  combined.match(/\bCHF\s*(\d+(?:[.,]\d{1,2})?)\b/i);
const readTimeMatch = combined.match(/\b(\d{1,3})\s*(?:min|mins|minutes?|minute|mn)\s+read\b/i);
const durationMatch = readTimeMatch ? null : combined.match(/\b(\d{1,3})(?:\s*[-–]\s*\d{1,3})?\s*(?:min|mins|minutes?|minute|mn)\b/i);
const securitySubject = /\b(connexion inhabituelle|unusual login|unusual sign-?in|login attempt|security alert|code de connexion|code de verification|mot de passe|password reset|verify your account|v[eé]rification)\b/i.test(subject);

const keywordTests = [
  { name: 'survey', regex: /\b(sondage|enqu[eê]te|survey|poll|questionnaire|umfrage|befragung)\b/i },
  { name: 'opinion', regex: /\b(votre avis compte|your opinion|avis|opinion)\b/i },
  { name: 'reward', regex: /\b(chf|récompense|reward|vergütung|bonus)\b/i },
  { name: 'duration', regex: /\b(min|minutes?|minute)\b/i, disabled: Boolean(readTimeMatch) },
  { name: 'invite', regex: /\b(invitation|invite|invited|einladung)\b/i },
  { name: 'start', regex: /\b(commencer|start|continue|participer|teilnehmen)\b/i },
];

const matchedKeywords = keywordTests
  .filter((k) => !k.disabled && k.regex.test(combined))
  .map((k) => k.name);
const highIntentKeywordCount = matchedKeywords.filter((name) => ['survey', 'opinion', 'invite', 'start'].includes(name)).length;

let score = 0;
if (trustedSender) score += 5;
if (taskLink) score += 4;
if (rewardMatch) score += 3;
if (durationMatch) score += 2;
score += Math.min(matchedKeywords.length, 4);

let classification = 'ignore';
if (senderAllowed && (trustedSender || rewardMatch || durationMatch || highIntentKeywordCount >= 2 || (taskLink && highIntentKeywordCount >= 1))) {
  classification = 'unclear_review';
}
if (senderAllowed && taskLink && (rewardMatch || durationMatch || highIntentKeywordCount >= 2)) {
  classification = 'likely_task';
} else if (senderAllowed && ((rewardMatch && durationMatch) || (trustedSender && highIntentKeywordCount >= 1))) {
  classification = 'likely_task';
}
if (securitySubject) {
  classification = 'ignore';
  score = 0;
}

// --- Meinungsplatz autorun whitelist (explicit signal to agent) ---
const meinungsplatzSender = /meinungsplatz\.ch/i.test(fromEmail || '') || /meinungsplatz\.ch|espacedopinion/i.test(fromDisplay || '');
const meinungsplatzLink = taskLink ? /meinungsplatz\.ch\/m3click/i.test(taskLink) : false;
const rewardPresent = Boolean(rewardMatch);
const durationPresent = Boolean(durationMatch) || Boolean(readTimeMatch);
const accountMapped = accountName === 'Арсена' || accountName === 'Олени';
const meinungsplatzAutorun = !securitySubject && meinungsplatzSender && meinungsplatzLink && rewardPresent && durationPresent && accountMapped;
let taskConfirmed = false;
let autoExecute = false;
let whitelistMatch = '';
if (meinungsplatzAutorun) {
  classification = 'likely_task';
  taskConfirmed = true;
  autoExecute = true;
  whitelistMatch = 'meinungsplatz_autorun';
}

const shouldInvokeAgent = senderAllowed && classification !== 'ignore';
const reward = rewardMatch ? rewardMatch[1].replace(',', '.') + ' CHF' : 'невідомо';
const duration = durationMatch ? durationMatch[1] + ' min' : 'невідомо';
const excerptSource = htmlText || text || subject || '';
const excerpt = excerptSource.replace(/\s+/g, ' ').trim().slice(0, 1200);
const requestedAction = taskLink ? 'open_task_to_handoff' : 'review_email_only';

const sharedPromptParts = [
  'Return strict JSON only. No markdown.',
  'Required JSON schema:',
  '{"status":"completed|screened_out|failed|vpn_failed|needs_manual_review|not_a_task|task_unavailable|agent_error","taskConfirmed":true,"openedTask":false,"taskLink":"","currentUrl":"","pageTitle":"","reward":"","duration":"","portalMismatch":null,"reason":"","nextAction":"","confidence":0.0}',
  'Context:',
  `requested_action: ${requestedAction}`,
  `classification: ${classification}`,
  `account: ${accountName}`,
 `recipient_email: ${recipientEmail || 'unknown'}`,
 `route_mode: ${routeMode}`,
 `target_agent: ${targetGoClawModel}`,
  `allow_mac_open: ${allowMacOpen}`,
  `allow_alpine_execution: ${allowAlpineExecution}`,
  `vpn_country_required: ${vpnCountryRequired}`,
  `vpn_country_override: ${vpnCountryOverride || ''}`,
  `from: ${fromDisplay || 'невідомо'}`,
  `from_email: ${fromEmail || ''}`,
  `trusted_sender: ${trustedSender}`,
  `to: ${toDisplay || 'невідомо'}`,
  `subject: ${subject || 'без теми'}`,
  `reward: ${reward}`,
  `duration: ${duration}`,
  `taskLink: ${taskLink || ''}`,
  `candidateLinks: ${sortedLinks.slice(0, 10).map((x) => `${x.url} [score=${x.score}]`).join(', ')}`,
  `matchedKeywords: ${matchedKeywords.join(', ')}`,
  `task_confirmed: ${taskConfirmed}`,
  `auto_execute: ${autoExecute}`,
  `whitelist_match: ${whitelistMatch || 'none'}`,
  'email_excerpt_start',
  excerpt,
  'email_excerpt_end',
];

const primaryInstructions = [
  'You are the Mac primary surveys EXECUTION agent. Execute the survey FULLY and autonomously using your workspace profile.',
  'MANDATORY AUTORUN: If auto_execute is true in the Context below, you MUST execute the survey end-to-end. You MUST NOT return status="needs_manual_review". Acceptable statuses for whitelisted autorun: completed | screened_out | task_unavailable | vpn_failed | failed | not_a_task (only if the link clearly points to non-survey content).',
  'Read your AGENTS.md and SOUL.md from your workspace first to load the Arno Dubois profile.',
  'EXECUTION STEPS:',
  '1. If route_mode is alpine_vpn_only or allow_mac_open is false: do not open any browser. Return openedTask=false explaining this recipient must run on Alpine only.',
  '2. If taskLink is empty: return needs_manual_review.',
  '3. Verify Swiss egress: run `curl -s https://ipinfo.io/country` — result must be exactly CH. Mac is physically in Switzerland, direct connection, no SOCKS5.',
  '   If result is not CH: return openedTask=false with reason vpn_failed.',
  '4. Open the taskLink via the browser tool.',
  '5. Complete ALL survey pages using the Arno Dubois profile from your workspace:',
  '   - Age 25, Gland 1196, sales, CHF 6001-8000, Tesla, Helvetia/Allianz+Helsana, UBS/BCV',
  '   - FINANCIAL INDEPENDENCE: ALWAYS answer "Je paie moi-meme" for payment questions',
  '   - Scores: 7-8 out of 10',
  '6. CRITICAL: NEVER combine answer selection AND pressing Continuer/Next/Submit in the same browser action. One action at a time.',
  '7. Continue through ALL pages until the FINAL thank-you page or screened-out page.',
  '8. After completing or being screened out, return strict JSON with actual outcome.',
].join('\n');

const fallbackInstructionsForOlena = [
  'You are the Alpine surveys EXECUTION agent (Olena / Annet Buonassie). Execute the survey FULLY and autonomously using your workspace profile.',
  'MANDATORY AUTORUN: If auto_execute is true in the Context below, you MUST execute the survey end-to-end. You MUST NOT return status="needs_manual_review". Acceptable statuses for whitelisted autorun: completed | screened_out | task_unavailable | vpn_failed | failed | not_a_task (only if the link clearly points to non-survey content).',
  'Read your AGENTS.md and SOUL.md from the surveys-olena workspace first to load the Annet Buonassie profile.',
  'EXECUTION STEPS:',
  '1. Verify Swiss egress via SOCKS5: run `curl -s --socks5-hostname 100.100.74.9:9888 https://ipinfo.io/country`',
  '   OR if vpn_country_override is present, use it as the diagnostic result.',
  '   If result is not CH: return openedTask=false with reason vpn_failed — Swiss VPN is not active.',
  '2. Open the taskLink via the browser tool using Swiss SOCKS5 proxy (100.100.74.9:9888).',
  '3. Complete ALL survey pages using the Annet Buonassie profile from your workspace:',
  '   - Age 52, Gland 1196, sales, CHF 6001-8000, Tesla, la Mubilière+Helsana, Salt, Revolut',
  '   - Scores: 7 out of 10, Agreement: Oui, plutôt d\'accord',
  '4. CRITICAL: NEVER combine answer selection AND pressing Continuer/Next in the same browser action. One action at a time.',
  '5. Continue through ALL pages until the FINAL thank-you page or screened-out page.',
  '6. After completing or being screened out, run the result pipeline:',
  '   source ~/.goclaw/surveys/.env && ~/.goclaw/surveys/scripts/run_survey_result.sh olena alpine',
  '7. Return strict JSON with actual outcome.',
].join('\n');

const fallbackInstructionsForArsen = [
  'You are the Alpine FALLBACK surveys EXECUTION agent for Arsen (Arno Dubois). Mac primary is unavailable. Execute the survey FULLY and autonomously using your workspace profile.',
  'MANDATORY AUTORUN: If auto_execute is true in the Context below, you MUST execute the survey end-to-end. You MUST NOT return status="needs_manual_review". Acceptable statuses for whitelisted autorun: completed | screened_out | task_unavailable | vpn_failed | failed | not_a_task (only if the link clearly points to non-survey content).',
  'Read your AGENTS.md and SOUL.md from the surveys-arsen workspace first to load the Arno Dubois profile.',
  'EXECUTION STEPS:',
  '1. Verify Swiss egress via SOCKS5: run `curl -s --socks5-hostname 100.100.74.9:9888 https://ipinfo.io/country`',
  '   OR if vpn_country_override is present, use it as the diagnostic result.',
  '   If result is not CH: return openedTask=false with reason vpn_failed — Swiss VPN is not active.',
  '2. Open the taskLink via the browser tool using Swiss SOCKS5 proxy (100.100.74.9:9888).',
  '3. Complete ALL survey pages using the Arno Dubois profile from your workspace:',
  '   - Age 25, Gland 1196, sales, CHF 6001-8000, Tesla, Helvetia/Allianz+Helsana, UBS/BCV',
  '   - FINANCIAL INDEPENDENCE: ALWAYS answer "Je paie moi-meme" for payment questions',
  '   - Scores: 7-8 out of 10',
  '4. CRITICAL: NEVER combine answer selection AND pressing Continuer/Next in the same browser action. One action at a time.',
  '5. Continue through ALL pages until the FINAL thank-you page or screened-out page.',
  '6. After completing or being screened out, run the result pipeline:',
  '   source ~/.goclaw/surveys/.env && ~/.goclaw/surveys/scripts/run_survey_result.sh arsen alpine',
  '7. Return strict JSON with actual outcome.',
].join('\n');

const fallbackInstructions = routeMode === 'alpine_vpn_only'
  ? fallbackInstructionsForOlena
  : fallbackInstructionsForArsen;

const buildMessage = (header, instructions) => [header, instructions, ...sharedPromptParts].join('\n\n');

const primaryGoclawRequestBody = {
 model: targetGoClawModel,
  messages: [
    {
      role: 'user',
      content: buildMessage('Primary host: Mac.', primaryInstructions),
    },
  ],
};

const fallbackGoclawRequestBody = {
 model: targetGoClawModel,
  messages: [
    {
      role: 'user',
      content: buildMessage(routeMode === 'alpine_vpn_only' ? 'Execution host: Alpine Swiss-VPN route required.' : 'Fallback host: Alpine.', fallbackInstructions),
    },
  ],
};

return {
  json: {
    ...data,
    accountName,
    recipientEmail,
    routeMode,
    allowMacOpen,
    allowAlpineExecution,
    vpnCountryRequired,
    vpnCountryOverride,
    trustedSender,
    senderAllowed,
    fromDisplay,
    fromEmail,
    toDisplay,
    classification,
    shouldInvokeAgent,
    score,
    reward,
    duration,
    matchedKeywords,
    taskLink,
    taskLinkCandidates: sortedLinks.slice(0, 10),
    emailExcerpt: excerpt,
    requestedAction,
    workflowMarker,
    primaryBaseUrl,
    fallbackBaseUrl,
    primaryGoclawRequestBody,
    fallbackGoclawRequestBody,
    taskConfirmed,
    autoExecute,
    whitelistMatch,
    meinungsplatzAutorun,
  },
};

const source = $('Analyze Email + Extract Link').itemMatching(0).json;
const resp = $json || {};

const asText = (value) => {
  if (!value) return '';
  if (typeof value === 'string') return value;
  if (typeof value.message === 'string') return value.message;
  if (typeof value.description === 'string') return value.description;
  try { return JSON.stringify(value); } catch { return String(value); }
};

const items = Array.isArray(resp.data)
  ? resp.data
  : Array.isArray(resp.agents)
    ? resp.agents
    : Array.isArray(resp.body?.data)
      ? resp.body.data
      : Array.isArray(resp.body?.agents)
        ? resp.body.agents
        : [];

const surveysAgent = items.find((agent) => {
  if (!agent || typeof agent !== 'object') return false;
  const id = String(agent.id || '').toLowerCase();
  const slug = String(agent.slug || '').toLowerCase();
  const name = String(agent.name || '').toLowerCase();
  const agentKey = String(agent.agent_key || '').toLowerCase();
  const displayName = String(agent.display_name || '').toLowerCase();
  const model = String(agent.model || '').toLowerCase();
  return id === 'surveys' || slug === 'surveys' || name === 'surveys' || agentKey === 'surveys' || displayName === 'surveys' || model === 'goclaw:surveys';
});

const fallbackAvailable = Boolean(surveysAgent);
const failureReason = fallbackAvailable
  ? ''
  : asText(resp.error) || asText(resp.body?.error) || asText(resp.message) || 'Alpine GoClaw did not return a surveys agent.';
const executionHostLabel = source.routeMode === 'alpine_vpn_only' ? 'Alpine Swiss-VPN primary' : 'Alpine fallback';

const noAgentTelegramText = [
  source.routeMode === 'alpine_vpn_only'
    ? '⚠️ Alpine Swiss-VPN path не готовий до запуску surveys для цього recipient.'
    : '⚠️ Ні primary, ні fallback GoClaw не готові до запуску surveys.',
  `👤 Для: ${source.accountName || 'невідомо'}`,
  `📨 Тема: ${source.subject || 'без теми'}`,
  `🔗 Candidate link: ${source.taskLink || 'не знайдено'}`,
  source.routeMode === 'alpine_vpn_only'
    ? `🧯 Alpine reason: ${failureReason || 'surveys agent missing on Alpine'}`
    : `🖥 Primary reason: ${source.primaryFailureReason || 'primary unavailable'}`,
  source.routeMode === 'alpine_vpn_only'
    ? '👉 Що зробити: перевірити Swiss VPN route на Alpine. Mac не повинен відкривати цю задачу.'
    : `🧯 Fallback reason: ${failureReason || 'surveys agent missing on Alpine'}`,
].join('\n');

return {
  json: {
    ...source,
    fallbackAgentsResponseRaw: resp,
    executionHost: 'alpine',
    executionHostLabel,
    selectedGoClawAgent: surveysAgent?.id || 'surveys',
    fallbackAvailable,
    fallbackFailureReason: failureReason,
    goclawRunnableRequestBody: source.fallbackGoclawRequestBody,
    noAgentTelegramText,
  },
};

const source = $('Analyze Email + Extract Link').itemMatching(0).json;
const resp = $json || {};

const pickRawText = (obj) => {
  if (typeof obj.output_text === 'string' && obj.output_text.trim()) return obj.output_text.trim();
  if (typeof obj.text === 'string' && obj.text.trim()) return obj.text.trim();
  if (typeof obj.response?.output_text === 'string' && obj.response.output_text.trim()) return obj.response.output_text.trim();

  const collected = [];
  const visit = (value) => {
    if (!value) return;
    if (typeof value === 'string') {
      const trimmed = value.trim();
      if (trimmed) collected.push(trimmed);
      return;
    }
    if (Array.isArray(value)) {
      for (const item of value) visit(item);
      return;
    }
    if (typeof value === 'object') {
      if (typeof value.text === 'string') collected.push(value.text.trim());
      if (typeof value.output_text === 'string') collected.push(value.output_text.trim());
      if (value.content) visit(value.content);
      if (value.output) visit(value.output);
      if (value.result) visit(value.result);
      if (value.response) visit(value.response);
      if (value.data) visit(value.data);
    }
  };

  visit(obj.output);
  visit(obj.result);
  visit(obj.response);
  visit(obj.data);

  return collected.filter(Boolean).join('\n').trim();
};

const extractJson = (raw) => {
  if (!raw || typeof raw !== 'string') return null;
  const fenced = raw.match(/```(?:json)?\s*([\s\S]*?)```/i);
  const candidate = fenced ? fenced[1] : raw;
  const direct = candidate.trim();
  try { return JSON.parse(direct); } catch {}
  const first = candidate.indexOf('{');
  const last = candidate.lastIndexOf('}');
  if (first >= 0 && last > first) {
    const sliced = candidate.slice(first, last + 1);
    try { return JSON.parse(sliced); } catch {}
  }
  return null;
};

const toPercent = (value) => {
  if (typeof value !== 'number' || !Number.isFinite(value)) return '';
  return `${Math.round(value * 100)}%`;
};

const summarizeReason = (status, reason, rawText) => {
  const combined = `${reason || ''} ${rawText || ''}`.toLowerCase();
  if (status === 'not_a_task') {
    if (/beehiiv/.test(combined)) return 'розсилка beehiiv';
    if (/newsletter/.test(combined)) return 'інформаційна розсилка';
    if (/not survey/.test(combined) || /not a task/.test(combined)) return 'це не опитування';
  }
  if (status === 'completed') return 'завершено';
  if (status === 'screened_out') return 'відсіяно';
  if (status === 'vpn_failed') return 'VPN не активний';
  if (status === 'failed') return 'виконання завершилось помилкою';
  if (status === 'task_unavailable') return 'задача недоступна';
  if (status === 'needs_manual_review') return 'потрібна ручна перевірка';
  if (status === 'agent_error') return 'GoClaw не зміг коректно обробити лист';
  return reason || '';
};

const shouldAppendReason = (status, summary) => {
  if (!summary) return false;
  const normalized = summary.trim().toLowerCase();
  if (status === 'needs_manual_review' && normalized === 'потрібна ручна перевірка') return false;
  if (status === 'task_unavailable' && normalized === 'задача недоступна') return false;
  if (status === 'agent_error' && normalized === 'goclaw не зміг коректно обробити лист') return false;
  return true;
};

const rawText = pickRawText(resp);
const parsed = extractJson(rawText);

let status = 'agent_error';
let taskConfirmed = false;
let openedTask = false;
let taskLink = source.taskLink || '';
