];

if (status === 'not_a_task') {
  lines.push(`⚪️ Не задача${reasonSummary ? ` — ${reasonSummary}` : ''}${confidenceText ? ` (впевненість ${confidenceText})` : ''}`);
  lines.push('🗑 Відхилено');
} else if (status === 'ready_for_handoff') {
  lines.push(`✅ Задача підтверджена${confidenceText ? ` (впевненість ${confidenceText})` : ''}`);
  lines.push(`🖥 Маршрут: ${hostLabel}`);
  if (reward && reward !== 'невідомо') lines.push(`💰 ${reward}`);
  if (duration && duration !== 'невідомо') lines.push(`⏱ ${duration}`);
  if (handoffLink) lines.push(`🔗 Handoff: ${htmlEscape(handoffLink)}`);
} else if (status === 'needs_manual_review') {
  lines.push(`🟡 Потрібна ручна перевірка${shouldAppendReason(status, reasonSummary) ? ` — ${reasonSummary}` : ''}${confidenceText ? ` (впевненість ${confidenceText})` : ''}`);
  if (reward && reward !== 'невідомо') lines.push(`💰 ${reward}`);
  if (duration && duration !== 'невідомо') lines.push(`⏱ ${duration}`);
  if (taskLink) lines.push(`🔗 Лінк: ${htmlEscape(taskLink)}`);
} else if (status === 'completed') {
  lines.push('✅ Опитування завершено');
  if (reward && reward !== 'невідомо') lines.push(`💰 Нагорода: ${reward}`);
} else if (status === 'screened_out') {
  lines.push('🚫 Відсіяно (screened out)');
  if (reward && reward !== 'невідомо') lines.push(`💰 ${reward}`);
} else if (status === 'vpn_failed') {
  lines.push('🔴 VPN не активний — Swiss IP не підтверджено (не CH)');
} else if (status === 'failed') {
  lines.push(`🔴 Виконання завершилось помилкою${shouldAppendReason(status, reasonSummary) ? ` — ${reasonSummary}` : ''}`);
  if (reward && reward !== 'невідомо') lines.push(`💰 ${reward}`);
} else if (status === 'task_unavailable') {
  lines.push(`🔴 Задача недоступна${shouldAppendReason(status, reasonSummary) ? ` — ${reasonSummary}` : ''}${confidenceText ? ` (впевненість ${confidenceText})` : ''}`);
  if (reward && reward !== 'невідомо') lines.push(`💰 ${reward}`);
  if (duration && duration !== 'невідомо') lines.push(`⏱ ${duration}`);
  if (taskLink) lines.push(`🔗 Лінк: ${htmlEscape(taskLink)}`);
} else {
  lines.push(`⚠️ Помилка обробки${shouldAppendReason(status, reasonSummary) ? ` — ${reasonSummary}` : ''}`);
  if (reward && reward !== 'невідомо') lines.push(`💰 ${reward}`);
  if (duration && duration !== 'невідомо') lines.push(`⏱ ${duration}`);
  if (taskLink) lines.push(`🔗 Лінк: ${htmlEscape(taskLink)}`);
}

if (pageTitle && status === 'ready_for_handoff') lines.push(`🪟 Сторінка: ${htmlEscape(pageTitle)}`);
if (portalMismatch === true) lines.push('🧭 Увага: відкрито інший портал');

return {
