const data = $json || {};

const asString = (value) => {
  if (value === null || value === undefined) return '';
  if (typeof value === 'string') return value;
  try {
    return JSON.stringify(value);
  } catch {
    return String(value);
  }
};

const htmlToText = (html) => asString(html)
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/gi, ' ')
  .replace(/&amp;/gi, '&')
  .replace(/&quot;/gi, '"')
  .replace(/&#39;/gi, "'")
  .replace(/\s+/g, ' ')
  .trim();

const extractAddress = (value) => {
  if (!value) return '';
  if (typeof value === 'string') {
    const match = value.match(/<?([A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,})>?/i);
    return match ? match[1].toLowerCase() : value.trim().toLowerCase();
  }
  if (Array.isArray(value)) {
    for (const item of value) {
      const found = extractAddress(item);
      if (found) return found;
    }
    return '';
  }
  if (typeof value === 'object') {
    if (typeof value.address === 'string') return value.address.trim().toLowerCase();
    if (Array.isArray(value.value)) {
      for (const item of value.value) {
        const found = extractAddress(item);
        if (found) return found;
      }
    }
    if (typeof value.text === 'string') {
      const found = extractAddress(value.text);
      if (found) return found;
    }
  }
  return '';
};

const formatAddress = (value) => {
  if (!value) return '';
  if (typeof value === 'string') return value.trim();
  if (Array.isArray(value)) {
    const items = value.map((item) => formatAddress(item)).filter(Boolean);
    return items.join(', ');
  }
  if (typeof value === 'object') {
    if (Array.isArray(value.value) && value.value.length > 0) {
      const first = value.value[0] || {};
      const name = asString(first.name).trim();
      const address = asString(first.address).trim();
      if (name && address) return `${name} <${address}>`;
      return name || address || asString(value.text).trim();
    }
    if (typeof value.text === 'string') return value.text.trim();
    const name = asString(value.name).trim();
    const address = asString(value.address).trim();
    if (name && address) return `${name} <${address}>`;
    return name || address;
  }
  return asString(value).trim();
};

