const rawLinks = [...(`${text}\n${html}`).matchAll(/https?:\/\/[^\s<>"')\]]+/gi)].map((m) => m[0]);
const cleanLink = (url) => asString(url).trim().replace(/[),.;]+$/g, '').replace(/&amp;/g, '&');
const uniqueLinks = [...new Set([...hrefLinks, ...rawLinks].map(cleanLink).filter(Boolean))];

const scoreLink = (url) => {
  const u = url.toLowerCase();
  let score = 0;
  if (/meinungsplatz|survey|sondage|enquete|questionnaire|poll|study|task|invite|invitation|continue|start|befrag|umfrage/.test(u)) score += 6;
  if (/token=|auth=|session=|survey=|questionnaire=|invite=|invitation=/.test(u)) score += 3;
  if (/unsubscribe|privacy|impress|contact|help|support|facebook|instagram|linkedin|twitter|x\.com|beehiiv/.test(u)) score -= 10;
  if (/https?:\/\//.test(u)) score += 1;
  return score;
};

const sortedLinks = uniqueLinks
  .map((url) => ({ url, score: scoreLink(url) }))
