const source = $('Analyze Email + Extract Link').itemMatching(0).json;
const resp = $json || {};

const pickRawText = (obj) => {
  if (typeof obj.output_text === 'string' && obj.output_text.trim()) return obj.output_text.trim();
  if (typeof obj.text === 'string' && obj.text.trim()) return obj.text.trim();
  if (typeof obj.response?.output_text === 'string' && obj.response.output_text.trim()) return obj.response.output_text.trim();

  const collected = [];
  const visit = (value) => {
    if (!value) return;
    if (typeof value === 'string') {
      const trimmed = value.trim();
      if (trimmed) collected.push(trimmed);
      return;
    }
    if (Array.isArray(value)) {
      for (const item of value) visit(item);
      return;
    }
    if (typeof value === 'object') {
      if (typeof value.text === 'string') collected.push(value.text.trim());
      if (typeof value.output_text === 'string') collected.push(value.output_text.trim());
      if (value.content) visit(value.content);
      if (value.output) visit(value.output);
      if (value.result) visit(value.result);
      if (value.response) visit(value.response);
      if (value.data) visit(value.data);
    }
  };

  visit(obj.output);
  visit(obj.result);
  visit(obj.response);
  visit(obj.data);

  return collected.filter(Boolean).join('\n').trim();
};

const extractJson = (raw) => {
  if (!raw || typeof raw !== 'string') return null;
  const fenced = raw.match(/```(?:json)?\s*([\s\S]*?)```/i);
  const candidate = fenced ? fenced[1] : raw;
  const direct = candidate.trim();
  try { return JSON.parse(direct); } catch {}
  const first = candidate.indexOf('{');
  const last = candidate.lastIndexOf('}');
  if (first >= 0 && last > first) {
    const sliced = candidate.slice(first, last + 1);
    try { return JSON.parse(sliced); } catch {}
  }
  return null;
};

const toPercent = (value) => {
  if (typeof value !== 'number' || !Number.isFinite(value)) return '';
  return `${Math.round(value * 100)}%`;
};

const summarizeReason = (status, reason, rawText) => {
  const combined = `${reason || ''} ${rawText || ''}`.toLowerCase();
  if (status === 'not_a_task') {
    if (/beehiiv/.test(combined)) return 'розсилка beehiiv';
    if (/newsletter/.test(combined)) return 'інформаційна розсилка';
    if (/not survey/.test(combined) || /not a task/.test(combined)) return 'це не опитування';
  }
  if (status === 'completed') return 'завершено';
  if (status === 'screened_out') return 'відсіяно';
  if (status === 'vpn_failed') return 'VPN не активний';
  if (status === 'failed') return 'виконання завершилось помилкою';
  if (status === 'task_unavailable') return 'задача недоступна';
  if (status === 'needs_manual_review') return 'потрібна ручна перевірка';
  if (status === 'agent_error') return 'GoClaw не зміг коректно обробити лист';
  return reason || '';
};

const shouldAppendReason = (status, summary) => {
  if (!summary) return false;
  const normalized = summary.trim().toLowerCase();
  if (status === 'needs_manual_review' && normalized === 'потрібна ручна перевірка') return false;
  if (status === 'task_unavailable' && normalized === 'задача недоступна') return false;
  if (status === 'agent_error' && normalized === 'goclaw не зміг коректно обробити лист') return false;
  return true;
};

const rawText = pickRawText(resp);
const parsed = extractJson(rawText);

let status = 'agent_error';
let taskConfirmed = false;
let openedTask = false;
let taskLink = source.taskLink || '';
let handoffLink = source.taskLink || '';
let reason = 'GoClaw did not return valid strict JSON.';
let nextAction = 'manual_review';
let pageTitle = '';
let reward = source.reward || 'невідомо';
let duration = source.duration || 'невідомо';
let portalMismatch = null;
let confidence = null;

if (parsed && typeof parsed === 'object') {
  status = parsed.status || (parsed.taskConfirmed ? 'ready_for_handoff' : 'needs_manual_review');
  taskConfirmed = Boolean(parsed.taskConfirmed);
  openedTask = Boolean(parsed.openedTask);
  taskLink = parsed.taskLink || taskLink;
  handoffLink = parsed.handoffLink || parsed.resumeUrl || parsed.currentUrl || taskLink;
  reason = parsed.reason || reason;
  nextAction = parsed.nextAction || nextAction;
  pageTitle = parsed.pageTitle || parsed.title || '';
  reward = parsed.reward || reward;
  duration = parsed.duration || duration;
  portalMismatch = Object.prototype.hasOwnProperty.call(parsed, 'portalMismatch') ? parsed.portalMismatch : portalMismatch;
  confidence = typeof parsed.confidence === 'number' ? parsed.confidence : confidence;
}

// --- Whitelist safety net: if Analyze marked taskConfirmed but agent still
//     refused with needs_manual_review, escalate to task_unavailable so we
//     don't tell the user to do whitelisted surveys manually.
if (source.taskConfirmed === true && status === 'needs_manual_review') {
  status = 'task_unavailable';
  reason = `Whitelist autorun (${source.whitelistMatch || 'meinungsplatz_autorun'}) but agent refused: ${reason || 'no detail'}`;
  nextAction = 'auto_retry';
}

const hostLabel = $input.item.json.executionHostLabel || source.executionHostLabel || (source.routeMode === 'alpine_vpn_only' ? 'Alpine' : 'Mac');
const confidenceText = toPercent(confidence);
const reasonSummary = summarizeReason(status, reason, rawText);

const htmlEscape = s => String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const quoteSubject = source.subject ? `"${htmlEscape(source.subject)}"` : '"без теми"';
let lines = [
  `📨 Лист: ${quoteSubject}`,
  `👤 Від: ${htmlEscape(source.fromDisplay || 'невідомо')}`,
  `🧭 Для: ${source.accountName || 'невідомо'}`,
];

if (status === 'not_a_task') {
  lines.push(`⚪️ Не задача${reasonSummary ? ` — ${reasonSummary}` : ''}${confidenceText ? ` (впевненість ${confidenceText})` : ''}`);
  lines.push('🗑 Відхилено');
} else if (status === 'ready_for_handoff') {
  lines.push(`✅ Задача підтверджена${confidenceText ? ` (впевненість ${confidenceText})` : ''}`);
  lines.push(`🖥 Маршрут: ${hostLabel}`);
  if (reward && reward !== 'невідомо') lines.push(`💰 ${reward}`);
  if (duration && duration !== 'невідомо') lines.push(`⏱ ${duration}`);
  if (handoffLink) lines.push(`🔗 Handoff: ${htmlEscape(handoffLink)}`);
} else if (status === 'needs_manual_review') {
  lines.push(`🟡 Потрібна ручна перевірка${shouldAppendReason(status, reasonSummary) ? ` — ${reasonSummary}` : ''}${confidenceText ? ` (впевненість ${confidenceText})` : ''}`);
  if (reward && reward !== 'невідомо') lines.push(`💰 ${reward}`);
  if (duration && duration !== 'невідомо') lines.push(`⏱ ${duration}`);
  if (taskLink) lines.push(`🔗 Лінк: ${htmlEscape(taskLink)}`);
} else if (status === 'completed') {
  lines.push('✅ Опитування завершено');
  if (reward && reward !== 'невідомо') lines.push(`💰 Нагорода: ${reward}`);
} else if (status === 'screened_out') {
  lines.push('🚫 Відсіяно (screened out)');
  if (reward && reward !== 'невідомо') lines.push(`💰 ${reward}`);
} else if (status === 'vpn_failed') {
  lines.push('🔴 VPN не активний — Swiss IP не підтверджено (не CH)');
} else if (status === 'failed') {
  lines.push(`🔴 Виконання завершилось помилкою${shouldAppendReason(status, reasonSummary) ? ` — ${reasonSummary}` : ''}`);
  if (reward && reward !== 'невідомо') lines.push(`💰 ${reward}`);
} else if (status === 'task_unavailable') {
  lines.push(`🔴 Задача недоступна${shouldAppendReason(status, reasonSummary) ? ` — ${reasonSummary}` : ''}${confidenceText ? ` (впевненість ${confidenceText})` : ''}`);
  if (reward && reward !== 'невідомо') lines.push(`💰 ${reward}`);
  if (duration && duration !== 'невідомо') lines.push(`⏱ ${duration}`);
  if (taskLink) lines.push(`🔗 Лінк: ${htmlEscape(taskLink)}`);
} else {
  lines.push(`⚠️ Помилка обробки${shouldAppendReason(status, reasonSummary) ? ` — ${reasonSummary}` : ''}`);
  if (reward && reward !== 'невідомо') lines.push(`💰 ${reward}`);
  if (duration && duration !== 'невідомо') lines.push(`⏱ ${duration}`);
  if (taskLink) lines.push(`🔗 Лінк: ${htmlEscape(taskLink)}`);
}

if (pageTitle && status === 'ready_for_handoff') lines.push(`🪟 Сторінка: ${htmlEscape(pageTitle)}`);
if (portalMismatch === true) lines.push('🧭 Увага: відкрито інший портал');

return {
  json: {
    ...source,
    ...$input.item.json,
    executionHostLabel: hostLabel,
    goclawRawResponse: resp,
    goclawRawText: rawText,
    goclawParsed: parsed,
    goclawStatus: status,
    taskConfirmed,
    openedTask,
    finalTaskLink: taskLink,
    handoffLink,
    portalMismatch,
    goclawReason: reason,
    goclawNextAction: nextAction,
    telegramText: lines.filter(Boolean).join('\n'),
  },
};

